const e=require("fs"),i=require("fs").readdirSync,s=e.readFileSync("tailwind-compiled.min.css","utf8"),l=e.readFileSync("style.min.css","utf8");i(".").filter(e=>e.endsWith(".html")).forEach(i=>{let t=e.readFileSync(i,"utf8");t=t.replace(/<link rel="stylesheet" href="tailwind-compiled\.min\.css[^"]*">/gi,`<style data-inline-src="tailwind-compiled.min.css">${s}</style>`),t=t.replace(/<link rel="stylesheet" href="style\.min\.css[^"]*">/gi,`<style data-inline-src="style.min.css">${l}</style>`),t=t.replace(/<style data-inline-src="tailwind-compiled\.min\.css">[\s\S]*?<\/style>/gi,`<style data-inline-src="tailwind-compiled.min.css">${s}</style>`),t=t.replace(/<style data-inline-src="style\.min\.css">[\s\S]*?<\/style>/gi,`<style data-inline-src="style.min.css">${l}</style>`),e.writeFileSync(i,t),console.log("Inlined CSS in "+i)});